55	const PROCESSING_FEE_GOLD = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
59	  sword: 100,
60	  amulet: 60,
61	  staff: 80,
62	  potion: 40,
63	  rune: 25,
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const BLOCK_SIZE = 3;
68	const BLOCK_BASE_PREMIUM = 60;
69	
70	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
71	
72	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
73	
74	const countByType = (items: Item[]): Map<string, number> =>
75	  items.reduce(
76	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
77	    new Map<string, number>(),
78	  );
79	
80	const groupPremium = (type: string, count: number): number =>
81	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM_BY_TYPE[type];
82	
83	const componentBasePremium = (items: Item[]): number => {
84	  const counts = countByType(items.filter(isComponent));
85	  return [...counts].reduce((sum, [type, count]) => sum + groupPremium(type, count), 0);
86	};
87	
88	const totalBasePremium = (items: Item[]): number => {
89	  const mainItemsTotal = items
90	    .filter((item) => !isComponent(item))
91	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
92	  return mainItemsTotal + componentBasePremium(items);
93	};
94	
95	const withFirstInsuranceSurcharge = (premium: number): number =>
96	  premium + premium * FIRST_INSURANCE_SURCHARGE_RATE;
97	
98	const quotePremium = (items: Item[]): number =>
99	  Math.ceil(withFirstInsuranceSurcharge(totalBasePremium(items)) + PROCESSING_FEE_GOLD);
100	
101	const runStep = (step: Step): StepResult => {
102	  if (step.op === "quote") return { premium: quotePremium(step.items) };
103	  return { payout: 0, remainingCap: 0 };
104	};
105	
106	export const runScenario = (scenario: Scenario): ScenarioResult => ({
107	  results: scenario.steps.map(runStep),
108	});
